+package github.chains;
+
+import java.io.File;
+import java.util.ArrayList;
+import java.util.List;
+import spoon.Launcher;
+import spoon.processing.AbstractProcessor;
+import spoon.reflect.code.CtInvocation;
+import spoon.reflect.declaration.CtImport;
+import spoon.reflect.declaration.CtType;
+import spoon.reflect.reference.CtTypeReference;
+import spoon.reflect.visitor.filter.TypeFilter;
+
+public class Main {
+
+    private static final String OLD_PUBLISH_METADATA = "com.google.cloud.pubsublite.PublishMetadata";
+    private static final String NEW_MESSAGE_METADATA = "com.google.cloud.pubsublite.MessageMetadata";
+    private static final String SET_CONTEXT = "setContext";
+    private static final String SINGLE_PARTITION_BUILDER =
+            "com.google.cloud.pubsublite.internal.wire.SinglePartitionPublisherBuilder.Builder";
+
+    public static void main(String[] args) {
+        if (args.length < 1) {
+            throw new IllegalArgumentException("Usage: Main <input-source-dir> [output-dir]");
+        }
+
+        String inputDir = args[0];
+        String outputDir = args.length > 1 ? args[1] : inputDir;
+
+        Launcher launcher = new Launcher();
+        launcher.getEnvironment().setNoClasspath(true);
+        launcher.getEnvironment().setAutoImports(true);
+        launcher.addInputResource(inputDir);
+        launcher.setSourceOutputDirectory(new File(outputDir));
+        launcher.addProcessor(new DependencyUpdateProcessor());
+        launcher.buildModel();
+        launcher.process();
+        launcher.prettyprint();
+    }
+
+    private static final class DependencyUpdateProcessor extends AbstractProcessor<CtType<?>> {
+
+        @Override
+        public boolean isToBeProcessed(CtType<?> type) {
+            return true;
+        }
+
+        @Override
+        public void process(CtType<?> type) {
+            replacePublishMetadataReferences(type);
+            removeLegacySetContextInvocations(type);
+            removeNowUnusedImports(type);
+        }
+
+        private void replacePublishMetadataReferences(CtType<?> type) {
+            List<CtTypeReference<?>> references = new ArrayList<>(type.getElements(new TypeFilter<>(CtTypeReference.class)));
+            for (CtTypeReference<?> reference : references) {
+                if (OLD_PUBLISH_METADATA.equals(reference.getQualifiedName())) {
+                    reference.setSimpleName("MessageMetadata");
+                    reference.setPackage(type.getFactory().Package().get(NEW_MESSAGE_METADATA.substring(0, NEW_MESSAGE_METADATA.lastIndexOf('.'))));
+                }
+            }
+        }
+
+        private void removeLegacySetContextInvocations(CtType<?> type) {
+            List<CtInvocation<?>> invocations = new ArrayList<>(type.getElements(new TypeFilter<>(CtInvocation.class)));
+            for (CtInvocation<?> invocation : invocations) {
+                if (!SET_CONTEXT.equals(invocation.getExecutable().getSimpleName())) {
+                    continue;
+                }
+                CtTypeReference<?> targetType = invocation.getTarget() == null ? null : invocation.getTarget().getType();
+                if (targetType != null && SINGLE_PARTITION_BUILDER.equals(targetType.getQualifiedName())) {
+                    invocation.delete();
+                }
+            }
+        }
+
+        private void removeNowUnusedImports(CtType<?> type) {
+            List<CtImport> imports = new ArrayList<>(type.getFactory().CompilationUnit().getFactory().CompilationUnit().getImports());
+            for (CtImport ctImport : imports) {
+                String importName = ctImport.getReference().getQualifiedName();
+                if (OLD_PUBLISH_METADATA.equals(importName)) {
+                    ctImport.setReference(type.getFactory().createCtTypeReference(NEW_MESSAGE_METADATA));
+                }
+            }
+        }
+    }
+}
*** End Patch

